function nodeRows(name) {
  return $items(name).flatMap((item) => {
    if (Array.isArray(item.json)) return item.json;
    if (Array.isArray(item.json.data)) return item.json.data;
    return Object.keys(item.json || {}).length ? [item.json] : [];
  });
}
function decode(value) {
  return String(value || '').replace(/&nbsp;/g, ' ').replace(/&amp;|&#038;/g, '&').replace(/&#8211;|&ndash;/g, '-').replace(/&#x27;|&#39;/g, String.fromCharCode(39)).replace(/&quot;|&#34;/g, String.fromCharCode(34));
}
function strip(value) {
  return decode(value).replace(/<!--[\s\S]*?-->/g, ' ').replace(/<script[\s\S]*?<\/script>/gi, ' ').replace(/<style[\s\S]*?<\/style>/gi, ' ').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
}
function parsePifaDate(text) {
  const match = text.match(/As of\s+(\d{2})\/(\d{2})\/(\d{4})/i);
  if (!match) throw new Error('Could not find PIFA source date. Sample: ' + text.slice(0, 400));
  return match[3] + '-' + match[1] + '-' + match[2];
}
function parseBpiDate(text) {
  const match = text.match(/Investment Funds Daily Monitor data as of ([A-Za-z]+)\s+(\d{1,2}),\s*(\d{4})/i);
  if (!match) return null;
  const months = { jan: '01', feb: '02', mar: '03', apr: '04', may: '05', jun: '06', jul: '07', aug: '08', sep: '09', oct: '10', nov: '11', dec: '12' };
  return match[3] + '-' + months[match[1].slice(0, 3).toLowerCase()] + '-' + String(match[2]).padStart(2, '0');
}
function roundRate(value) { return Number(value.toFixed(6)); }
function parseBpiRows(text) {
  const matches = [...text.matchAll(/(ALFM Money Market Fund(?: \(Units\))?)\s+([\d,.]+)\s+-?\d+(?:\.\d+)?%\s+-?\d+(?:\.\d+)?%\s+(-?\d+(?:\.\d+)?)%/gi)];
  if (matches.length < 2) return null;
  return {
    'alfm-money-market-fund-shares': { navpu: Number(matches[0][2].replace(/,/g, '')), gross_yield: Number(matches[0][3]) / 100 },
    'alfm-money-market-fund-units': { navpu: Number(matches[1][2].replace(/,/g, '')), gross_yield: Number(matches[1][3]) / 100 },
  };
}
const funds = nodeRows('Get Mutual Fund Targets').filter((row) => row.id);
if (!funds.length) throw new Error('No mutual-fund targets returned from Supabase');
const benchmarks = nodeRows('Get Latest Benchmark').filter((row) => row.rate !== undefined && row.rate !== null);
if (!benchmarks.length) throw new Error('Missing BTR_91D benchmark. Run the BTr benchmark workflow first.');
const benchmarkRate = Number(benchmarks[0].rate);
const benchmarkAfterTaxRate = benchmarkRate * 0.8;
const pifaRaw = $items('Fetch PIFA Facts Figures')[0].json.data || $items('Fetch PIFA Facts Figures')[0].json.body || $items('Fetch PIFA Facts Figures')[0].json.html || '';
const bpiRaw = $items('Fetch BPI Funds Monitor')[0].json.data || $items('Fetch BPI Funds Monitor')[0].json.body || $items('Fetch BPI Funds Monitor')[0].json.html || '';
const pifaText = strip(typeof pifaRaw === 'string' ? pifaRaw : JSON.stringify(pifaRaw || {}));
const bpiText = strip(typeof bpiRaw === 'string' ? bpiRaw : JSON.stringify(bpiRaw || {}));
const sourceDate = parsePifaDate(pifaText);
const alfmRows = [...pifaText.matchAll(/(ALFM Money Market Fund, Inc\.)\s+([\d,.]+)\s+(-?\d+(?:\.\d+)?)%/gi)];
if (alfmRows.length < 2) throw new Error('Could not parse both ALFM rows from PIFA');
const sourceRows = {
  'alfm-money-market-fund-shares': { navpu: Number(alfmRows[0][2].replace(/,/g, '')), gross_yield: Number(alfmRows[0][3]) / 100 },
  'alfm-money-market-fund-units': { navpu: Number(alfmRows[1][2].replace(/,/g, '')), gross_yield: Number(alfmRows[1][3]) / 100 },
};
const fami = pifaText.match(/First Metro Save and Learn Money Market Fund, Inc\.\s+([\d,.]+)\s+(-?\d+(?:\.\d+)?)%/i);
if (!fami) throw new Error('Could not parse FAMI row from PIFA');
sourceRows['fami-save-and-learn-money-market-fund'] = { navpu: Number(fami[1].replace(/,/g, '')), gross_yield: Number(fami[2]) / 100 };
const bpiDate = parseBpiDate(bpiText);
const bpiRows = parseBpiRows(bpiText);
if (bpiDate === sourceDate && bpiRows) {
  for (const slug of ['alfm-money-market-fund-shares', 'alfm-money-market-fund-units']) {
    const pifa = sourceRows[slug];
    const bpi = bpiRows[slug];
    if (Math.abs(pifa.navpu - bpi.navpu) > 0.0001 || Math.abs(pifa.gross_yield - bpi.gross_yield) > 0.000001) {
      throw new Error('ALFM cross-check mismatch for ' + slug + ': PIFA ' + JSON.stringify(pifa) + ', BPI ' + JSON.stringify(bpi));
    }
  }
}
const output = [];
const missing = [];
for (const fund of funds) {
  const row = sourceRows[fund.slug];
  if (!row) { missing.push(fund.provider + ' - ' + fund.name); continue; }
  const netYield = row.gross_yield;
  output.push({ json: { fund_id: fund.id, date: sourceDate, navpu: row.navpu, gross_yield_1y: roundRate(row.gross_yield), after_tax_yield: roundRate(row.gross_yield), net_yield: roundRate(netYield), benchmark_rate: roundRate(benchmarkRate), vs_benchmark: roundRate(netYield - benchmarkAfterTaxRate), data_source: 'scraper' } });
}
if (missing.length) throw new Error('Missing PIFA mutual-fund rows for: ' + missing.join('; '));
return output;
